27→    @Operation(summary = "Create External Notify")
28→    public ResponseData<CreateNotifyVo> createExternalNotify(@RequestBody @Valid CreateExternalNotifyRo ro) {
29→        log.info("createExternalNotify: spaceId={}, templateId={}, sourceSystem={}",
30→                ro.getSpaceId(), ro.getTemplateId(), ro.getSourceSystem());
31→        CreateNotifyVo result = apitableGrpcClientService.createExternalNotify(
32→                ro.getToUserEmails(),
33→                ro.getSpaceId(),
34→                ro.getTemplateId(),
35→                ro.getFromUserEmail(),
36→                ro.getNotifyBody(),
37→                ro.getNodeId(),
38→                ro.getSourceSystem()
39→        );
40→        return ResponseData.success(result);
