150→    @Bean
151→    public Declarables nextcloudWebhookShardDeclarables() {
152→        DirectExchange exchange = new DirectExchange(NEXTCLOUD_WEBHOOK_DIRECT_EXCHANGE);
153→        List<Declarable> items = new ArrayList<>();
154→        for (int i = 0; i < NEXTCLOUD_WEBHOOK_SHARD_COUNT; i++) {
155→            Queue queue = QueueBuilder.durable(NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + i).build();
156→            String routingKey = NEXTCLOUD_WEBHOOK_SHARD_ROUTING_KEY_PREFIX + i;
157→            items.add(queue);
158→            items.add(BindingBuilder.bind(queue).to(exchange).with(routingKey));
159→        }
160→        return new Declarables(items);
161→    }
162→
163→    /**
164→     * Nextcloud 分片消费专用 ContainerFactory：
165→     * 使用批量回调 + AUTO ACK（监听方法成功返回后 ack，抛异常后 reject 且不 requeue）。
166→     * 通过 receiveTimeout 控制 2s 收包窗口，同 shard 单消费者保证顺序。
167→     */
168→    @Bean
169→    public SimpleRabbitListenerContainerFactory nextcloudShardBatchContainerFactory(ConnectionFactory connectionFactory,
170→                                                                                    NextcloudProperties nextcloudProperties) {
171→        NextcloudProperties.Callback callback = nextcloudProperties.getCallback();
172→        int batchMaxSize = Math.max(callback.getBatchMaxSize(), 1);
173→        long receiveTimeoutMs = Math.max(callback.getBatchReceiveTimeoutMs(), 1);
174→        int concurrency = Math.max(callback.getConsumerConcurrencyPerShard(), 1);
175→
176→        SimpleRabbitListenerContainerFactory factory = new SimpleRabbitListenerContainerFactory();
177→        factory.setConnectionFactory(connectionFactory);
178→        factory.setConcurrentConsumers(concurrency);
179→        factory.setMaxConcurrentConsumers(concurrency);
180→        factory.setBatchListener(true);
181→        factory.setConsumerBatchEnabled(true);
182→        factory.setBatchSize(batchMaxSize);
183→        factory.setPrefetchCount(batchMaxSize);
184→        factory.setReceiveTimeout(receiveTimeoutMs);
185→        factory.setAcknowledgeMode(AcknowledgeMode.AUTO);
186→        factory.setDefaultRequeueRejected(false);
187→        return factory;
188→    }
189→
