 38→ * 结合TextWebSocketHandler和SocketIO客户端功能
 39→ */
 40→@Slf4j
 41→@Component
 42→public class WebSocketHandler extends TextWebSocketHandler {
 43→
 44→
 45→    @Resource
 46→    private RedisTemplate<String, Object> redisTemplate;
 47→
 48→
 49→    private final TextMessage heart = new TextMessage("ru");
 50→
 51→
 52→    private static final ConcurrentHashMap<String, WSUserModel> USER_SOCKET_SESSION_MAP;
 53→
 54→
 55→    static {
 56→        USER_SOCKET_SESSION_MAP = new ConcurrentHashMap<String, WSUserModel>(12);
 57→    }
 58→
 59→    public Map<String, WSUserModel> getCurrentUserMap() {
 60→        return Collections.unmodifiableMap(USER_SOCKET_SESSION_MAP);
 61→    }
