 63→
 64→    /**
 65→     * 前台连接并且注册了账户
 66→     */
 67→    @Override
 68→    public void afterConnectionEstablished(WebSocketSession session) throws Exception {
 69→        log.info("afterConnectionEstablished");
 70→
 71→        session.setTextMessageSizeLimit(50 * 1024); // 消息大小设置为50KB 不够用再扩展
 72→        session.setBinaryMessageSizeLimit(50 * 1024);
 73→        openConn(session);
 74→    }
 75→
