202→    private int sendToMatchedSockets(String message, Set<Long> targetUserIds, Set<String> targetSocketKeys) {
203→        int sendCount = 0;
204→        TextMessage textMessage = new TextMessage(message);
205→        for (Map.Entry<String, WSUserModel> entry : USER_SOCKET_SESSION_MAP.entrySet()) {
206→            String socketKey = entry.getKey();
207→            WSUserModel wsUserModel = entry.getValue();
208→            if (!isMatchedSocket(socketKey, wsUserModel, targetUserIds, targetSocketKeys)) {
209→                continue;
210→            }
211→            WebSocketSession session = wsUserModel.getWs();
212→            if (session == null || !session.isOpen()) {
213→                USER_SOCKET_SESSION_MAP.remove(socketKey);
214→                continue;
215→            }
216→            try {
217→                synchronized (session) {
218→                    session.sendMessage(textMessage);
219→                }
220→                sendCount++;
221→            } catch (IOException e) {
222→                log.error("向WebSocket客户端发送消息失败 - 用户: {}, 错误: {}", socketKey, e.getMessage());
223→                USER_SOCKET_SESSION_MAP.remove(socketKey);
224→            }
225→        }
226→        return sendCount;
227→    }
228→
229→    private boolean isMatchedSocket(String socketKey, WSUserModel wsUserModel,
230→                                    Set<Long> targetUserIds, Set<String> targetSocketKeys) {
231→        boolean matchedByUser = CollectionUtils.isEmpty(targetUserIds);
232→        if (!matchedByUser) {
233→            Long userId = wsUserModel.getUserId();
234→            matchedByUser = userId != null && targetUserIds.contains(userId);
235→        }
236→        if (!matchedByUser) {
237→            return false;
238→        }
239→        return CollectionUtils.isEmpty(targetSocketKeys) || targetSocketKeys.contains(socketKey);
240→    }
