312→
313→    private void closeConn(WebSocketSession session, boolean isError) {
314→        WSUserModel wsUserModel = new WSUserModel(session);
315→        WSUserModel.webSocketMapRemove(USER_SOCKET_SESSION_MAP, wsUserModel);
316→
317→        if (isError) {
318→            log.info("窗口关闭(Error) wsId:{}, gridKey:{}", wsUserModel.getId(), wsUserModel.getGridKey());
319→        } else {
320→            log.info("窗口关闭 wsId:{}, gridKey:{}", wsUserModel.getId(), wsUserModel.getGridKey());
321→            try {
322→                WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.success(MessageTypeEnum.CONNECT_CLOSE.getDesc(), null);
323→                ObjectMapper obj = new ObjectMapper();
324→                String params = obj.writeValueAsString(webSocketResponseModel);
325→                sendMessageToWs(session, params);
326→            } catch (Exception ex) {
327→                log.error("closeConn--Exception:" + ex);
328→            }
329→        }
330→
331→    }
