411→    @PostResource(path = "/batchUpdateAICitation", externalOnly = true)
412→    @Parameters({
413→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
414→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
415→    })
416→    @Operation(summary = "Batch Update Document AI Citation")
417→    public ResponseData<Void> batchUpdateAICitation(@RequestBody @Valid BatchUpdateAICitationRo ro) {
418→        Long userId = SessionContext.getUserId();
419→        if (!ro.getNodeIds().isEmpty()) {
420→            // AI 引用批量设置（仅文档）：这里沿用“节点维度”的 AI_ENABLE 权限做鉴权。
421→            // 说明：
422→            // - 当前仅对列表中的第一个节点做权限校验；后续批量节点的权限与空间隔离由 updateManager 内部的存在性/类型校验兜底。
423→            // - 若未来需要更严格的权限模型（例如每个节点分别校验/或校验同一父目录权限），应在此处扩展。
424→            permissionChecker.requireUser(userId).onNode(ro.getNodeIds().getFirst()).needPermission(NodePermission.AI_ENABLE);
425→        }
426→        // 进入业务链路：逐个节点校验（存在/类型）+ 父级文件夹策略覆盖判断（覆盖则返回 610）+ 更新 aiEnable 字段
427→        spaceNodeUpdateManager.batchUpdateAICitation(ro);
428→        return ResponseData.success();
429→    }
