 55→    public void handle(CreateNodeEvent event) {
 56→        Integer type = event.getType();
 57→        SpaceNodeTypeEnum spaceNodeType = SpaceNodeTypeEnum.fromValue(type);
 58→        
 59→        switch (spaceNodeType) {
 60→            case MIRROR -> handleMirrorNode(event);
 61→            case FORM -> handleFormNode(event);
 62→            case DATASHEET -> handleDataSheetNode(event);
 63→            default -> log.warn("not handle this type : {}", type);
 64→        }
 65→    }
 66→
 67→    private void handleDataSheetNode(CreateNodeEvent event) {
 68→        Long userId = event.getOperatorId();
 69→        String spaceId = event.getSpaceId();
 70→        String nodeId = event.getNodeId();
 71→        String nodeName = event.getNodeName();
 72→
 73→        log.info("received form: spaceId: {}, userId: {}, nodeId: {}", spaceId, userId, nodeId);
 74→
 75→        if(CollectionUtils.isNotEmpty(spaceNodeService.listByAppSpaceNodeIds(List.of(nodeId)))) {
 76→            log.info("space node already exists, appSpaceNodeId: {}", nodeId);
 77→            return;
 78→        }
 79→        log.info("space node not exists, appSpaceNodeId: {}", nodeId);
 80→        TreeNode<SpaceNodeVo> spaceNodeOnlyInAio = spaceNodeUpdateManager.createSpaceNodeOnlyInAio(spaceId, ROOT_PARENT_ID, nodeId, nodeName, SpaceNodeTypeEnum.DATASHEET.getThirdValue());
 81→
 82→        nodeRoleUpdateManager.handleRoleByCreate(userId,spaceId,spaceNodeOnlyInAio.getData().getId());
 83→
 84→        if (ragDocNotifyPublisher != null) {
 85→            SpaceNodeEntity createdEntity = new SpaceNodeEntity();
 86→            createdEntity.setId(spaceNodeOnlyInAio.getData().getId());
 87→            createdEntity.setSpaceId(spaceId);
 88→            createdEntity.setType(SpaceNodeTypeEnum.DATASHEET.getValue());
 89→            ragDocNotifyPublisher.publishDocChange(createdEntity);
 90→        }
 91→
 92→    }
