 94→    private void handleMirrorNode(CreateNodeEvent event) {
 95→        Long userId = event.getOperatorId();
 96→        String spaceId = event.getSpaceId();
 97→        String nodeId = event.getNodeId();
 98→        String nodeName = event.getNodeName();
 99→        String originDatasheetId = event.getOriginDatasheetId();
100→
101→        log.info("received mirror: spaceId: {}, userId: {}, nodeId: {}, originDatasheetId: {}", spaceId, userId, nodeId, originDatasheetId);
102→
103→        //校验真正的父层级
104→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(List.of(originDatasheetId));
105→        if (CollectionUtils.isNotEmpty(spaceNodeEntities)) {
106→            SpaceNodeEntity originSpaceNodeEntity = spaceNodeEntities.getFirst();
107→            NodeEntity originNodeEntity = nodeService.getByRelId(originSpaceNodeEntity.getId());
108→            if(null==originNodeEntity){
109→                log.error("{}node不存在", originDatasheetId);
110→                return;
111→            }
112→            Long parentId = originNodeEntity.getParentId();
113→            boolean checkResult = spaceNodeQueryManager.checkNameWithParent(spaceId, nodeName, parentId);
114→            if(!checkResult) {
115→                log.error("{}已存在重名文件/文件夹", nodeName);
116→                return;
117→            }
118→        }else{
119→            log.error("{}不存在", originDatasheetId);
120→            return;
121→        }
122→
123→
124→        TreeNode<SpaceNodeVo> mirror = spaceNodeUpdateManager.createSpaceNodeOnlyInAioNoCheck(spaceId, ROOT_PARENT_ID, nodeId, nodeName, SpaceNodeTypeEnum.MIRROR.getThirdValue());
125→        moveNodeToOriginParent(originDatasheetId, mirror.getId());
126→
127→        nodeRoleUpdateManager.handleRoleByCreate(userId,spaceId,mirror.getData().getId());
128→
129→        if (ragDocNotifyPublisher != null) {
130→            SpaceNodeEntity mirrorEntity = new SpaceNodeEntity();
131→            mirrorEntity.setId(mirror.getData().getId());
132→            mirrorEntity.setSpaceId(spaceId);
133→            mirrorEntity.setType(SpaceNodeTypeEnum.MIRROR.getValue());
134→            ragDocNotifyPublisher.publishDocChange(mirrorEntity);
135→        }
136→    }
137→
138→    private void handleFormNode(CreateNodeEvent event) {
139→        Long userId = event.getOperatorId();
140→        String spaceId = event.getSpaceId();
141→        String nodeId = event.getNodeId();
142→        String nodeName = event.getNodeName();
143→        String originDatasheetId = event.getOriginDatasheetId();
144→
145→        log.info("received form: spaceId: {}, userId: {}, nodeId: {}, originDatasheetId: {}", spaceId, userId, nodeId, originDatasheetId);
146→
147→        //校验真正的父层级
148→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(List.of(originDatasheetId));
149→        if (CollectionUtils.isNotEmpty(spaceNodeEntities)) {
150→            SpaceNodeEntity originSpaceNodeEntity = spaceNodeEntities.getFirst();
151→            NodeEntity originNodeEntity = nodeService.getByRelId(originSpaceNodeEntity.getId());
152→            if(null==originNodeEntity){
153→                log.error("{}node不存在", originDatasheetId);
154→                return;
155→            }
156→            Long parentId = originNodeEntity.getParentId();
157→
158→            nodeName = spaceNodeQueryManager.checkAndGenNameWithParent(spaceId, nodeName, parentId);
159→
160→
161→        }else{
162→            log.error("{}不存在", originDatasheetId);
163→            return;
164→        }
165→
166→        TreeNode<SpaceNodeVo> form = spaceNodeUpdateManager.createSpaceNodeOnlyInAioNoCheck(spaceId, ROOT_PARENT_ID, nodeId, nodeName, SpaceNodeTypeEnum.FORM.getThirdValue());
167→        moveNodeToOriginParent(originDatasheetId, form.getId());
168→
169→        nodeRoleUpdateManager.handleRoleByCreate(userId,spaceId,form.getData().getId());
170→
171→        //sync
172→        NameSyncContext ctx = NameSyncContext.builder().spaceId(spaceId).userId(userId).name(nodeName).appSpaceNodeId(nodeId).build();
173→        appSpaceNodeActionFactory.getNameSyncable(SpaceNodeTypeEnum.FORM).syncName(ctx);
174→
175→        if (ragDocNotifyPublisher != null) {
176→            SpaceNodeEntity formEntity = new SpaceNodeEntity();
177→            formEntity.setId(form.getData().getId());
178→            formEntity.setSpaceId(spaceId);
179→            formEntity.setType(SpaceNodeTypeEnum.FORM.getValue());
180→            ragDocNotifyPublisher.publishDocChange(formEntity);
181→        }
182→
183→    }
