16→@Slf4j
17→@Component
18→public class PermissionBroadcaster {
19→
20→    private List<PermissionSyncable> handlers;
21→
22→    private final ApplicationContext applicationContext;
23→
24→    public PermissionBroadcaster(ApplicationContext applicationContext) {
25→        this.applicationContext = applicationContext;
26→    }
27→
28→    @PostConstruct
29→    public void init() {
30→        Map<String, PermissionSyncable> beans = applicationContext.getBeansOfType(PermissionSyncable.class);
31→        handlers = new ArrayList<>(beans.values());
32→    }
33→
34→    public void broadcast(String spaceId, List<SpaceNodeUserRoleCacheEntity> changedRecords) {
35→        if (spaceId == null) {
36→            log.debug("Skip broadcast: spaceId is null");
37→            return;
38→        }
39→
40→        if (CollectionUtils.isEmpty(changedRecords)) {
41→            log.debug("No changed records to broadcast");
42→            return;
43→        }
44→
45→        if (CollectionUtils.isEmpty(handlers)) {
46→            log.debug("No sync handlers registered, skipping broadcast");
47→            return;
48→        }
49→
50→        log.info("Broadcasting {} permission changes for spaceId={}", changedRecords.size(), spaceId);
51→
52→        notifyHandlers(spaceId, changedRecords);
53→
54→    }
55→
56→    private void notifyHandlers(String spaceId, List<SpaceNodeUserRoleCacheEntity> records) {
57→        PermissionSyncContext ctx = PermissionSyncContext.builder()
58→                .spaceId(spaceId)
59→                .changedRecords(records)
60→                .build();
61→
62→        for (PermissionSyncable handler : handlers) {
63→            try {
64→                handler.syncPermission(ctx);
65→            } catch (Exception e) {
66→                log.error("Sync failed for handler: {}, spaceId={}, recordSize={}",
67→                        handler.getPermissionSyncType(), spaceId, records.size(), e);
68→            }
69→        }
70→    }
71→
72→}
