274→    /**
275→     * 新建节点时：根据父级设置 aiEnable。文件夹设 aiReferenceStatus=FOLLOW。
276→     */
277→    private void applyAiReferenceInheritance(SpaceNodeEntity entity, Long parentNodeId) {
278→        if (FOLDER.getValue().equals(entity.getType())) {
279→            entity.setAiReferenceStatus(AiReferenceStatusEnum.FOLLOW.getValue());
280→            log.info("[AI Ref] Create folder: nodeId={}, name={}, parentId={}, aiReferenceStatus=FOLLOW",
281→                    entity.getId(), entity.getName(), parentNodeId);
282→        }
283→        boolean aiEnable = resolveAiEnableFromParent(parentNodeId);
284→        entity.setAiEnable(aiEnable);
285→        log.info("[AI Ref] Create node: nodeId={}, name={}, parentId={}, aiEnable={}",
286→                entity.getId(), entity.getName(), parentNodeId, aiEnable);
287→    }
288→
289→    /**
290→     * 新增时检查父级：根据父级（或祖先链）解析 aiEnable。父为文件夹时查其 aiReferenceStatus；
291→     * 父为 FOLLOW 时取父的 aiEnable（已反映祖先级联）。文件和文件夹均需检查。
292→     */
293→    private boolean resolveAiEnableFromParent(Long parentNodeId) {
294→        if (parentNodeId == null || parentNodeId == 0L) return true;
295→        NodeEntity parentNode = nodeService.getById(parentNodeId);
296→        if (parentNode == null) return true;
297→        SpaceNodeEntity parentSpace = spaceNodeService.getById(parentNode.getRelId());
298→        if (parentSpace == null || !FOLDER.getValue().equals(parentSpace.getType())) return true;
299→        Integer status = parentSpace.getAiReferenceStatus();
300→        if (status == null) status = AiReferenceStatusEnum.FOLLOW.getValue();
301→        if (AiReferenceStatusEnum.ALLOW.getValue().equals(status)) return true;
302→        if (AiReferenceStatusEnum.DENY.getValue().equals(status)) return false;
303→        // FOLLOW：父级继承自祖先，取父级的 aiEnable
304→        return Boolean.TRUE.equals(AiReferenceHelper.getAiEnable(parentSpace, parentSpace));
305→    }
306→
307→    /**
308→     * 移动节点后：子文件夹和文档永远跟父文件夹一样
309→     * - 子文件夹：继承父文件夹的 aiReferenceStatus
310→     * - 文档：继承父文件夹的 aiEnable
311→     * - 无父级（根目录）：设为 FOLLOW，aiEnable=true
312→     */
313→    private void applyAiReferenceAfterMove(Long spaceNodeId, Long newParentNodeId) {
314→        List<NodeEntity> subtree = nodeService.listSubtreeByRelId(spaceNodeId);
315→        log.info("[AI Ref] Move subtree: rootId={}, newParentId={}, subtreeSize={}",
316→                spaceNodeId, newParentNodeId, subtree.size());
317→        for (NodeEntity ne : subtree) {
318→            SpaceNodeEntity child = spaceNodeService.getById(ne.getRelId());
319→            if (child == null) continue;
320→            SpaceNodeEntity parent = aiReferenceHelper.getParentFolder(ne.getRelId());
321→
322→            if (parent != null) {
323→                // 有父级：子永远跟父一样
324→                Integer parentStatus = parent.getAiReferenceStatus();
325→                boolean parentAiEnable = Boolean.TRUE.equals(parent.getAiEnable());
326→                if (FOLDER.getValue().equals(child.getType())) {
327→                    // 子文件夹：继承父的 aiReferenceStatus
328→                    child.setAiReferenceStatus(parentStatus);
329→                    log.info("[AI Ref] Move folder follow parent: nodeId={}, name={}, aiReferenceStatus={}, aiEnable={}",
330→                            child.getId(), child.getName(), parentStatus, parentAiEnable);
331→                } else {
332→                    // 文档：继承父的 aiEnable
333→                    child.setAiEnable(AiReferenceHelper.getAiEnable(child,parent));
334→                    log.info("[AI Ref] Move doc follow parent: nodeId={}, name={}, aiEnable={}",
335→                            child.getId(), child.getName(), parentAiEnable);
336→                }
337→            }
338→            spaceNodeService.updateById(child);
339→        }
340→    }
