400→    @Override
401→    @Transactional
402→    public TreeNode<SpaceNodeVo> convertToNextcloud(String spaceId, Long userId, Long sourceNodeId) {
403→        spaceService.checkSpaceExist(spaceId);
404→
405→        // 1. 查询源节点
406→        SpaceNodeEntity sourceSpaceNode = spaceNodeService.getById(sourceNodeId);
407→        ExceptionUtil.isNotNull(sourceSpaceNode, DatabaseException.QUERY_EMPTY_BY_ID);
408→        log.info("[convertToNextcloud] sourceNodeId={}, type={}, name={}", sourceNodeId, sourceSpaceNode.getType(), sourceSpaceNode.getName());
409→
410→        // 2. 校验类型
411→        SpaceNodeTypeEnum sourceType = SpaceNodeTypeEnum.fromValue(sourceSpaceNode.getType());
412→        if (!SpaceNodeTypeEnum.CONVERTIBLE_TO_NEXTCLOUD_TYPES.contains(sourceType)) {
413→            throw new BusinessException("该类型不支持转换为NextCloud文件");
414→        }
415→        if (!spaceId.equals(sourceSpaceNode.getSpaceId())) {
416→            throw new BusinessException("源节点不属于当前空间");
417→        }
418→
419→        // 3. 记录源节点的树位置
420→        NodeEntity sourceNodeEntity = nodeService.getByRelId(sourceNodeId);
421→        ExceptionUtil.isNotNull(sourceNodeEntity, DatabaseException.QUERY_EMPTY_BY_ID);
422→        Long originalParentId = sourceNodeEntity.getParentId();
423→        Long originalPreId = sourceNodeEntity.getPreId();
424→        String baseName = stripFileExtension(sourceSpaceNode.getName());
425→
426→        // 4. 计算父节点路径（NC 文件要放到对应文件夹下）
427→        String parentPath = calculateParentPath(originalParentId);
428→        log.info("[convertToNextcloud] tree position: parentId={}, preId={}, baseName={}, parentPath={}", originalParentId, originalPreId, baseName, parentPath);
429→
430→        // 5. 导出源文件并上传到 NextCloud
431→        String ncFileId = exportAndUploadToNextcloud(sourceSpaceNode, sourceType, spaceId, baseName, parentPath);
432→        log.info("[convertToNextcloud] uploaded to NextCloud, ncFileId={}", ncFileId);
433→
434→        // 6. 软删除源节点
435→        deleteSpaceNode(sourceNodeId, userId);
436→        log.info("[convertToNextcloud] source node deleted, sourceNodeId={}", sourceNodeId);
437→
438→        // 7. 获取带后缀的文件名作为 AIO 节点名
439→        String ncNodeName = buildNcNodeName(baseName, sourceType);
440→
441→        // 8. 创建新的 NEXTCLOUD 节点（AIO 节点名带后缀）
442→        TreeNode<SpaceNodeVo> newNode = createSpaceNodeOnlyInAio(spaceId, originalParentId, ncFileId, ncNodeName, SpaceNodeTypeEnum.NEXTCLOUD.getValue());
443→        log.info("[convertToNextcloud] new NEXTCLOUD node created, newNodeId={}", newNode.getData().getId());
444→
445→        // 9. 移动到原位（用原来的 preId）
446→        treeNodeTemplate.moveNode(spaceId, newNode.getId(), originalPreId, originalParentId, SpaceNodeEntity.class);
447→        log.info("[convertToNextcloud] node moved to original position, done");
448→
449→        // 10. 复制原节点权限到新节点
450→        Long newSpaceNodeId = newNode.getData().getId();
451→        copyNodePermissions(spaceId, sourceNodeId, newSpaceNodeId);
452→
453→        return newNode;
454→    }
