456→    /**
457→     * 复制源节点的权限配置到新节点（control + control_role）
458→     */
459→    private void copyNodePermissions(String spaceId, Long sourceNodeId, Long newNodeId) {
460→        String sourceControlId = sourceNodeId.toString();
461→        String newControlId = newNodeId.toString();
462→
463→        // 检查源节点是否有自定义权限
464→        if (!controlService.existsByControlId(sourceControlId)) {
465→            log.info("[convertToNextcloud] source node has no custom permissions, skip copy");
466→            return;
467→        }
468→
469→        // 复制 control 记录
470→        ControlEntity sourceControl = controlService.getByControlId(sourceControlId);
471→        if (sourceControl != null) {
472→            ControlEntity newControl = ControlEntity.builder()
473→                    .spaceId(spaceId)
474→                    .controlId(newControlId)
475→                    .controlType(sourceControl.getControlType())
476→                    .build();
477→            controlService.save(newControl);
478→        }
479→
480→        // 复制 control_role 记录
481→        List<ControlRoleEntity> sourceRoles = controlRoleService.getByControlId(sourceControlId);
482→        if (sourceRoles != null && !sourceRoles.isEmpty()) {
483→            List<ControlRoleEntity> newRoles = new ArrayList<>();
484→            for (ControlRoleEntity role : sourceRoles) {
485→                newRoles.add(ControlRoleEntity.builder()
486→                        .controlId(newControlId)
487→                        .unitId(role.getUnitId())
488→                        .roleCode(role.getRoleCode())
489→                        .build());
490→            }
491→            controlRoleService.saveBatch(newRoles);
492→            log.info("[convertToNextcloud] copied {} permission roles from {} to {}", newRoles.size(), sourceControlId, newControlId);
493→        }
494→    }
