504→    private String exportAndUploadToNextcloud(SpaceNodeEntity sourceSpaceNode, SpaceNodeTypeEnum sourceType, String spaceId, String name, String parentPath) {
505→        NextcloudActionImpl nextcloudAction = getNextcloudAction();
506→        if (SpaceNodeTypeEnum.ONLYOFFICE_TYPES.contains(sourceType)) {
507→            String appSpaceNodeId = sourceSpaceNode.getAppSpaceNodeId();
508→            log.info("[convertToNextcloud] exporting OnlyOffice file, appSpaceNodeId={}", appSpaceNodeId);
509→            byte[] fileData = onlyofficeService.exportFile(appSpaceNodeId);
510→            if (fileData == null || fileData.length == 0) {
511→                throw new BusinessException("OnlyOffice文件导出失败");
512→            }
513→            log.info("[convertToNextcloud] OnlyOffice export success, size={} bytes", fileData.length);
514→            String fileSuffix = getOnlyofficeSuffix(sourceType);
515→            return nextcloudAction.importByBytes(fileData, spaceId, name, fileSuffix, parentPath);
516→        }
517→        if (sourceType == SpaceNodeTypeEnum.DATASHEET) {
518→            String dstId = sourceSpaceNode.getAppSpaceNodeId();
519→            log.info("[convertToNextcloud] exporting Datasheet, dstId={}", dstId);
520→            ExportLuckysheetResult exportResult = apitableGrpcClientService.exportDatasheetToMinio(dstId);
521→            if (exportResult == null || !Boolean.TRUE.equals(exportResult.getSuccess()) || StringUtils.isBlank(exportResult.getDownloadUrl())) {
522→                throw new BusinessException("Datasheet导出失败: " + (exportResult != null ? exportResult.getMessage() : "null"));
523→            }
524→            log.info("[convertToNextcloud] Datasheet export success, downloading from minio, fileName={}", exportResult.getFileName());
525→            byte[] fileData = cn.hutool.http.HttpUtil.downloadBytes(exportResult.getDownloadUrl());
526→            if (fileData == null || fileData.length == 0) {
527→                throw new BusinessException("Datasheet导出文件下载失败");
528→            }
529→            log.info("[convertToNextcloud] Datasheet download success, size={} bytes", fileData.length);
530→            String fileName = exportResult.getFileName();
531→            String fileSuffix = "";
532→            if (fileName != null && fileName.contains(".")) {
533→                fileSuffix = fileName.substring(fileName.lastIndexOf('.') + 1);
534→            }
535→            return nextcloudAction.importByBytes(fileData, spaceId, name, fileSuffix, parentPath);
536→        }
537→        throw new BusinessException("该类型的导出功能暂未实现");
538→    }
