553→    /**
554→     * 去掉文件名中已知的后缀（如 .xlsx, .doc 等），仅当后缀在 MimeTypeMapping 中有注册时才去掉
555→     */
556→    private String stripFileExtension(String name) {
557→        if (name == null || name.isBlank()) {
558→            return name;
559→        }
560→        int lastDot = name.lastIndexOf('.');
561→        if (lastDot <= 0) {
562→            return name;
563→        }
564→        String ext = name.substring(lastDot + 1).toLowerCase();
565→        if (MimeTypeMapping.extensionToMimeType(ext) != null) {
