26→@Slf4j
27→@Component
28→@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
29→public class AnnouncementConsumer {
30→    @Resource
31→    AnnouncementMapper announcementMapper;
32→
33→    @Resource
34→    WebSocketHandler webSocketHandler;
35→
36→    @Resource
37→    AnnouncementPushService announcementPushService;
38→
39→    @RabbitListener(queues = ANNOUNCEMENT_QUEUE)
40→    public void handle(Message message, Channel channel) throws IOException {
41→        log.info("Received announcement message: {}", message);
42→        String body = new String(message.getBody());
43→        Long announcementId = Long.parseLong(body);
44→        try {
45→        AnnouncementEntity announce = announcementMapper.selectById(announcementId);
46→        if (announce == null || announce.getStatus() == AnnouncementStatus.CANCELLED.getCode()
47→        || announce.getType() == AnnouncementType.DRAFT.getCode()) {
48→            throw new RuntimeException("公告不需要发布");
49→        }
50→        announce.setStatus(AnnouncementStatus.PUBLISHED.getCode());
51→        announce.setUpdatedAt(LocalDateTime.now());
52→        announcementMapper.updateById(announce);
53→
54→         WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.builder().type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
55→                    .message("更新公告").status(200).data(null).build();
56→         String msg = JSONUtil.toJsonStr(webSocketResponseModel);
57→         webSocketHandler.sendAllUserToWebSocketClient(msg);
58→
59→         // 同步推送到 Knock + MM
60→         announcementPushService.pushAnnouncement(announce);
61→        } catch (Exception e) {
62→            log.error("[lbl][2087-消息推送][Announcement][PUBLISH] 定时发布公告失败, id={}, error={}", announcementId, e.getMessage(), e);
63→        } finally {
64→            // 先不考虑重试
65→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
66→            channel.basicAck(deliveryTag, false);
67→        }
68→    }
69→}
